css:
* { margin: 0; padding: 0; box-sizing: border-box; }
body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; background: #0a0800; color: white; }
nav { display: flex; align-items: center; justify-content: space-between; padding: 0 72px; height: 72px; border-bottom: 1px solid rgba(234,179,8,0.15); position: sticky; top: 0; background: rgba(10,8,0,0.9); backdrop-filter: blur(20px); z-index: 100; }
.logo { font-size: 20px; font-weight: 800; color: #eab308; }
.links { display: flex; gap: 28px; } .links a { color: #6b7280; text-decoration: none; font-weight: 500; }
.ticket-btn { padding: 12px 24px; border-radius: 12px; border: none; background: #eab308; color: #0a0800; font-weight: 800; cursor: pointer; }
.hero { text-align: center; padding: 80px 72px; border-bottom: 1px solid rgba(255,255,255,0.07); }
.hero-badge { display: inline-block; color: #eab308; font-size: 14px; font-weight: 700; margin-bottom: 20px; }
h1 { font-size: 96px; font-weight: 900; line-height: 0.95; letter-spacing: -4px; margin-bottom: 24px; } h1 span { color: #eab308; }
.event-details { display: flex; justify-content: center; gap: 28px; margin-bottom: 20px; }
.ed-item { display: flex; align-items: center; gap: 8px; font-size: 15px; color: rgba(255,255,255,0.7); font-weight: 500; }
.hero p { color: #6b7280; font-size: 18px; line-height: 1.7; max-width: 600px; margin: 0 auto 32px; }
.hero-actions { display: flex; gap: 14px; justify-content: center; margin-bottom: 40px; }
.btn-ticket { padding: 18px 36px; border-radius: 16px; border: none; background: linear-gradient(135deg, #eab308, #d97706); color: #0a0800; font-weight: 900; font-size: 17px; cursor: pointer; }
.btn-program { padding: 18px 32px; border-radius: 16px; border: 1px solid rgba(255,255,255,0.2); background: transparent; color: white; font-weight: 600; font-size: 16px; cursor: pointer; }
.countdown { display: flex; justify-content: center; align-items: center; gap: 20px; }
.cd-item { text-align: center; } .cd-item strong { display: block; font-size: 48px; font-weight: 900; color: #eab308; } .cd-item span { font-size: 12px; color: #6b7280; letter-spacing: 2px; }
.cd-sep { font-size: 40px; color: #374151; margin-bottom: 16px; }
.speakers { padding: 80px 72px; border-bottom: 1px solid rgba(255,255,255,0.07); }
.speakers h2 { font-size: 42px; font-weight: 800; margin-bottom: 36px; }
.speakers-grid { display: grid; grid-template-columns: repeat(6, 1fr); gap: 16px; }
.speaker-card { text-align: center; padding: 24px 16px; border-radius: 16px; background: rgba(255,255,255,0.04); border: 1px solid rgba(255,255,255,0.07); transition: all 0.2s; } .speaker-card:hover { border-color: rgba(234,179,8,0.4); transform: translateY(-4px); }
.sp-avatar { font-size: 40px; margin-bottom: 12px; } .speaker-card strong { display: block; font-size: 14px; font-weight: 700; margin-bottom: 4px; } .speaker-card span { color: #6b7280; font-size: 12px; display: block; margin-bottom: 8px; }
.sp-topic { display: inline-block; padding: 4px 10px; border-radius: 20px; background: rgba(234,179,8,0.1); color: #eab308; font-size: 11px; font-weight: 700; }
.tickets { padding: 80px 72px; }
.tickets h2 { font-size: 42px; font-weight: 800; margin-bottom: 36px; text-align: center; }
.tickets-grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 20px; max-width: 860px; margin: 0 auto; }
.ticket-card { padding: 32px; border-radius: 20px; background: rgba(255,255,255,0.04); border: 1px solid rgba(255,255,255,0.08); position: relative; } .ticket-card.featured { background: rgba(234,179,8,0.08); border-color: rgba(234,179,8,0.4); transform: scale(1.04); }
.popular-badge { position: absolute; top: -12px; left: 50%; transform: translateX(-50%); background: #eab308; color: #0a0800; padding: 4px 16px; border-radius: 20px; font-size: 12px; font-weight: 800; white-space: nowrap; }
.ticket-card h3 { font-size: 22px; font-weight: 800; margin-bottom: 12px; }
.tc-price { font-size: 40px; font-weight: 900; color: #eab308; margin-bottom: 20px; }
.ticket-card ul { list-style: none; display: flex; flex-direction: column; gap: 10px; margin-bottom: 24px; }
.ticket-card li { font-size: 14px; color: rgba(255,255,255,0.7); } .ticket-card li.x { color: #374151; }
.tc-btn { width: 100%; height: 48px; border-radius: 14px; border: 1px solid rgba(255,255,255,0.2); background: transparent; color: white; font-weight: 700; cursor: pointer; font-size: 15px; transition: all 0.2s; } .tc-btn:hover { background: rgba(255,255,255,0.08); } .tc-btn.featured { background: #eab308; border-color: #eab308; color: #0a0800; } .tc-btn.featured:hover { background: #d97706; }

