function updateTimer() {
  const target = new Date('2025-03-15T09:00:00');
  const diff = target - new Date();
  if (diff <= 0) return;
  document.getElementById('d').textContent = String(Math.floor(diff/86400000)).padStart(2,'0');
  document.getElementById('h').textContent = String(Math.floor((diff%86400000)/3600000)).padStart(2,'0');
  document.getElementById('m').textContent = String(Math.floor((diff%3600000)/60000)).padStart(2,'0');
  document.getElementById('s').textContent = String(Math.floor((diff%60000)/1000)).padStart(2,'0');
}
setInterval(updateTimer,1000); updateTimer();
document.querySelectorAll('.tc-btn').forEach(btn => { btn.addEventListener('click', function() { const prev = this.textContent; this.textContent = '✓ Sepete Eklendi'; this.style.background = '#22c55e'; this.style.borderColor = '#22c55e'; this.style.color = 'white'; setTimeout(() => { this.textContent = prev; this.style.background = ''; this.style.borderColor = ''; this.style.color = ''; }, 2000); }); });
